const _locExpanded={};
function renderLocsAutoSummary(){
  const el=document.getElementById('locs-auto-summary');
  if(!el)return;
  const whereMap={};
  (D.goals||[]).filter(g=>!g.done).forEach(g=>{
    if(!g.where||!g.saved)return;
    const key=g.where.trim();if(!key)return;
    if(!whereMap[key])whereMap[key]={total:0,goals:[]};
    const sv=parseFloat(g.saved)||0;
    whereMap[key].total+=sv;
    if(g.name)whereMap[key].goals.push({name:g.name,saved:sv});
  });
  if(!Object.keys(whereMap).length){el.innerHTML='';return;}
  const keys=Object.keys(whereMap);
  let html=`<div style="font-size:11px;color:var(--teal);margin-bottom:8px;font-weight:600">🔄 מחושב אוטומטית מהמטרות הפעילות שלך:</div>`;
  html+=`<div style="background:var(--s2);border:1px solid var(--border);border-radius:10px;overflow:hidden;margin-bottom:10px">`;
  keys.forEach((where,idx)=>{
    const data=whereMap[where];
    const isExp=!!_locExpanded[where];
    const hasMore=idx<keys.length-1||isExp;
    html+=`<div onclick="toggleLocRow('${where.replace(/'/g,"\\'")}')" style="display:flex;justify-content:space-between;align-items:center;
      padding:10px 14px;${hasMore?'border-bottom:1px solid var(--border)':''}font-size:13px;cursor:pointer;user-select:none">
      <span style="color:var(--t2);display:flex;align-items:center;gap:6px">
        ${esc(where)} <span style="font-size:10px;color:var(--t3)">${isExp?'▲':'▼'}</span>
      </span>
      <span style="color:var(--teal);font-weight:700">${fmt(data.total)} ₪</span>
    </div>`;
    if(isExp){
      data.goals.forEach((gl,gi)=>{
        const isLastSub=gi===data.goals.length-1&&idx===keys.length-1;
        html+=`<div style="display:flex;justify-content:space-between;align-items:center;padding:6px 22px;
          ${!isLastSub?'border-bottom:1px solid var(--border)':''}background:rgba(0,0,0,.12)">
          <span style="font-size:12px;color:var(--t3)">↳ ${esc(gl.name)}</span>
          <span style="font-size:12px;color:var(--teal);font-weight:600">${fmt(gl.saved)} ₪</span>
        </div>`;
      });
    }
  });
  html+=`</div>`;
  el.innerHTML=html;
}
function toggleLocRow(where){_locExpanded[where]=!_locExpanded[where];renderLocsAutoSummary();}

function renderLocsRealloc(){
  const el=document.getElementById('locs-realloc');
  if(!el)return;
  const rows=(D.goals||[]).filter(g=>!g.done&&g.where&&g.saved);
  if(!rows.length){el.innerHTML='';return;}
  // group by whereTo (or "נשאר" if empty)
  const groups={};
  let grandTotal=0;
  rows.forEach(g=>{
    const dest=(g.whereTo||'').trim()||'נשאר במיקום הנוכחי';
    if(!groups[dest])groups[dest]={rows:[],total:0};
    const sv=parseFloat(g.saved)||0;
    groups[dest].rows.push({name:g.name||'ללא שם',from:g.where.trim(),amt:sv});
    groups[dest].total+=sv;
    grandTotal+=sv;
  });
  const destKeys=Object.keys(groups).sort((a,b)=>a==='נשאר במיקום הנוכחי'?1:b==='נשאר במיקום הנוכחי'?-1:0);
  let html=`<div style="font-size:11px;color:var(--teal);margin-bottom:8px;font-weight:600">🔀 חלוקת כספים חדשה — מחושב מהמטרות הפעילות:</div>
  <div style="background:var(--s2);border:1px solid var(--border);border-radius:10px;overflow:hidden">
  <div style="display:grid;grid-template-columns:1fr 1fr auto;gap:0;font-size:10px;font-weight:700;color:var(--t3);
    padding:8px 14px;border-bottom:1px solid var(--border);text-align:right">
    <span>מטרה</span><span>מיקום נוכחי</span><span style="text-align:left;min-width:90px">יעד חדש / סכום</span>
  </div>`;
  destKeys.forEach((dest,di)=>{
    const grp=groups[dest];
    const isLast=di===destKeys.length-1;
    const isStay=dest==='נשאר במיקום הנוכחי';
    html+=`<div style="padding:7px 14px;background:${isStay?'transparent':'rgba(66,235,214,.04)'};
      border-bottom:1px solid var(--border);display:flex;justify-content:space-between;align-items:center">
      <span style="font-size:11px;font-weight:700;color:${isStay?'var(--t2)':'var(--teal)'}">${isStay?'↩ נשאר במיקום הנוכחי':'→ '+esc(dest)}</span>
      <span style="font-size:13px;font-weight:800;color:${isStay?'var(--t2)':'var(--teal)'}">${fmt(grp.total)} ₪</span>
    </div>`;
    grp.rows.forEach((r,ri)=>{
      const isLastRow=ri===grp.rows.length-1&&isLast;
      html+=`<div style="display:grid;grid-template-columns:1fr 1fr auto;gap:0;align-items:center;
        padding:7px 14px 7px 22px;${!isLastRow||!isLast?'border-bottom:1px solid var(--border)':''}background:rgba(0,0,0,.1)">
        <span style="font-size:12px;color:var(--white)">${esc(r.name)}</span>
        <span style="font-size:11px;color:var(--t2)">${esc(r.from)}</span>
        <span style="font-size:12px;font-weight:600;color:var(--t2);text-align:left;min-width:90px">${fmt(r.amt)} ₪</span>
      </div>`;
    });
  });
  html+=`<div style="display:flex;justify-content:space-between;align-items:center;padding:10px 14px;
    background:rgba(66,235,214,.07);border-top:1px solid var(--teal-border)">
    <span style="font-size:12px;font-weight:700;color:var(--teal)">סה"כ כספים מוקצים</span>
    <span style="font-size:15px;font-weight:800;color:var(--teal)">${fmt(grandTotal)} ₪</span>
  </div></div>`;
  el.innerHTML=html;
}

// ══ HISTORY RESTORE + DELETE ══
async function restoreSnap(i){
  if(!confirm('שחזר את המצב מתמונת מצב זו?\n\nהמצב הנוכחי יישמר כתמונת מצב לפני השחזור.'))return;
  const snap=D.snapshots[i];
  if(!snap)return;
  const cur=calcCurrent(),now=new Date();
  D.snapshots.push({date:now.toISOString(),label:'לפני שחזור ('+snap.label+')',...cur});
  D.monthly=String(snap.monthly||'');
  if(snap.goals)D.goals=JSON.parse(JSON.stringify(snap.goals));
  if(snap.locations)D.locations=JSON.parse(JSON.stringify(snap.locations));
  await saveDataFS(CU,D);
  renderAll();showToast('המצב שוחזר ✓');
}
async function deleteSnapDirect(i){
  if(!confirm('למחוק תמונת מצב זו לצמיתות?'))return;
  D.snapshots.splice(i,1);
  await saveDataFS(CU,D);
  renderHistory();renderDash();showToast('נמחק ✓');
}

